import { StateCreator } from 'zustand';
// FIX: The GameStore type is defined in `types.ts`, not exported from the store module. Corrected the import path.
import { GameStore, GameSlice, GameState, GameSave, PlayerCharacter, Choice, Companion } from '../types';
import { getScene } from '../services/dataService';
import { db } from '../db';
import { addItemToInventory, formatCurrencyFromCopper, totalCurrencyInCopper } from '../lib/utils';
import { INVENTORY_SIZE } from '../constants';
import { EFFECT_REGISTRY } from '../services/effectRegistry';
import { FACTIONS } from '../data/factions';
import { CAMP_UPGRADES } from '../data/campUpgrades';

/**
 * Extracts the savable parts of the game state to be stored in the database.
 * Transient states like `combatState` are excluded.
 * @param state The current GameStore state.
 * @returns A `GameSave` object.
 */
const savableState = (state: GameStore): Omit<GameSave, 'id' | 'saveTimestamp'> => ({
  player: state.player,
  party: state.party,
  currentSceneId: state.currentSceneId,
  previousSceneId: state.previousSceneId,
  globalFlags: state.globalFlags,
  unlockedLoreIds: state.unlockedLoreIds,
  encounteredCreatureIds: state.encounteredCreatureIds,
  encounteredNpcIds: state.encounteredNpcIds,
  npcState: state.npcState,
  quests: state.quests,
  actionCounters: state.actionCounters,
  isLevelUpPending: state.isLevelUpPending,
  companionLevelUpInfo: state.companionLevelUpInfo,
  factionRelationsOverrides: state.factionRelationsOverrides,
  readDialogueIds: state.readDialogueIds,
  campUpgrades: state.campUpgrades,
});

/**
 * Creates a slice of the store that manages the core game flow.
 * This includes initializing a new game, advancing scenes, managing companions,
 * and handling save/load functionality. It acts as an orchestrator, calling
 * actions from other slices when necessary.
 * @param set - Zustand's `set` function.
 * @param get - Zustand's `get` function.
 * @returns An object containing the core game flow state and actions.
 */
export const createGameSlice: StateCreator<GameStore, [], [], GameSlice> = (set, get) => ({
    isHydrated: false,
    autosaveNotificationVisible: false,

    hydrate: (savedState) => {
      // Handle legacy saves that might have a single 'companion' instead of 'party'
      let party = savedState.party || [];
      if (!party.length && (savedState as any).companion) {
          party = [(savedState as any).companion];
      }

      set({ 
          ...savedState, 
          party, 
          combatState: null, 
          npcState: savedState.npcState || {}, 
          quests: savedState.quests || {}, 
          factionRelationsOverrides: savedState.factionRelationsOverrides || {}, 
          readDialogueIds: savedState.readDialogueIds || [], 
          campUpgrades: savedState.campUpgrades || [], 
          isHydrated: true 
        });
    },

    initializeNewGame: async (character: PlayerCharacter) => {
      const initialInventory = Array(INVENTORY_SIZE).fill(null);
      const populatedInventory = [...initialInventory];

      if(character.inventory) {
          character.inventory.forEach(slotData => {
              if (slotData) {
                  for(let i = 0; i < slotData.quantity; i++) {
                     const { inventory: newInv } = addItemToInventory(populatedInventory, slotData.item);
                     for(let j=0; j<newInv.length; j++) populatedInventory[j] = newInv[j];
                  }
              }
          })
      }

      const initialState: GameState = {
        player: {
            ...character,
            inventory: populatedInventory,
            level: 1,
            xp: 0,
            xpToNextLevel: 100,
            skills: [],
            feats: [],
            reputation: {},
        },
        party: [],
        currentSceneId: 'intro_portal',
        previousSceneId: null,
        globalFlags: {},
        unlockedLoreIds: [],
        encounteredCreatureIds: [],
        encounteredNpcIds: [],
        npcState: {},
        combatState: null,
        tradeSession: null,
        quests: {},
        isLevelUpPending: false,
        companionLevelUpInfo: null,
        actionCounters: {},
        factionRelationsOverrides: {},
        readDialogueIds: [],
        campUpgrades: [],
      };

      set({ ...initialState, isHydrated: true });
      await get().triggerAutosave();
    },

    advanceScene: async (choice) => {
      const { startQuest, updateQuest, completeQuest, triggerAutosave } = get();
      const previousScene = getScene(get().currentSceneId);
      const nextScene = await getScene(choice.nextScene || get().currentSceneId);

      // Handle quest state changes triggered by the choice
      if (choice.startsQuest) startQuest(choice.startsQuest);
      if (choice.updatesQuest) updateQuest(choice.updatesQuest.questId, choice.updatesQuest.objectiveId, choice.updatesQuest.status);
      if (choice.completesQuest) completeQuest(choice.completesQuest);

      // Handle quest state changes triggered by the upcoming scene
      if (nextScene?.startsQuest) startQuest(nextScene.startsQuest);
      if (nextScene?.updatesQuest) updateQuest(nextScene.updatesQuest.questId, nextScene.updatesQuest.objectiveId, nextScene.updatesQuest.status);
      if (nextScene?.completesQuest) completeQuest(nextScene.completesQuest);

      set(state => {
        let nextGameState = { ...state } as GameState;

        nextGameState = {
            ...nextGameState,
            previousSceneId: state.currentSceneId,
            currentSceneId: choice.nextScene || state.currentSceneId,
        };

        // --- LOGIC DECOUPLING ---
        // Instead of executing functions directly from data objects, we now use IDs
        // to look up and execute the corresponding logic from a centralized registry.

        // Apply effect from the selected choice, if it has one.
        if (choice.effectId && EFFECT_REGISTRY[choice.effectId]) {
          nextGameState = EFFECT_REGISTRY[choice.effectId](nextGameState);
        }
        // Apply effect from the upcoming scene, if it has one.
        if (nextScene?.effectId && EFFECT_REGISTRY[nextScene.effectId]) {
          nextGameState = EFFECT_REGISTRY[nextScene.effectId](nextGameState);
        }

        // --- Reputation Logic ---
        if (nextGameState.player) {
            let newReputation = { ...nextGameState.player.reputation };

            const applyReputationChange = (change: Record<string, number>) => {
                for (const factionId in change) {
                    const value = change[factionId];
                    // Direct change
                    newReputation[factionId] = (newReputation[factionId] || 0) + value;

                    // Cascading changes
                    const staticFactionData = FACTIONS.find(f => f.id === factionId);
                    const overrideData = nextGameState.factionRelationsOverrides?.[factionId];

                    // Merge static and override relations. Override takes precedence.
                    const finalRelations = {
                        allies: overrideData?.allies ?? staticFactionData?.relations?.allies ?? [],
                        enemies: overrideData?.enemies ?? staticFactionData?.relations?.enemies ?? []
                    };

                    if (value > 0) { // Gaining rep
                        finalRelations.allies.forEach(allyId => {
                            newReputation[allyId] = (newReputation[allyId] || 0) + Math.ceil(value / 2);
                        });
                        finalRelations.enemies.forEach(enemyId => {
                            newReputation[enemyId] = (newReputation[enemyId] || 0) - Math.ceil(value / 2);
                        });
                    } else if (value < 0) { // Losing rep
                        finalRelations.allies.forEach(allyId => {
                            newReputation[allyId] = (newReputation[allyId] || 0) + Math.floor(value / 2); // value is negative
                        });
                        finalRelations.enemies.forEach(enemyId => {
                            newReputation[enemyId] = (newReputation[enemyId] || 0) - Math.floor(value / 2); // gains rep with enemies
                        });
                    }
                }
            };
            if (choice.reputationChange) applyReputationChange(choice.reputationChange);
            if (nextScene?.reputationChange) applyReputationChange(nextScene.reputationChange);

            nextGameState.player.reputation = newReputation;
        }


        // Handle unlocks
        const unlocks = { ...choice.unlocks, ...nextScene?.unlocks };
        const loreToUnlock = new Set<string>(nextGameState.unlockedLoreIds);
        const creaturesToUnlock = new Set<string>(nextGameState.encounteredCreatureIds);
        const npcsToUnlock = new Set<string>(nextGameState.encounteredNpcIds);

        unlocks.lore?.forEach(id => loreToUnlock.add(id));
        unlocks.creatures?.forEach(id => creaturesToUnlock.add(id));
        unlocks.npcs?.forEach(id => npcsToUnlock.add(id));

        nextGameState.unlockedLoreIds = Array.from(loreToUnlock);
        nextGameState.encounteredCreatureIds = Array.from(creaturesToUnlock);
        nextGameState.encounteredNpcIds = Array.from(npcsToUnlock);

        return nextGameState;
      });

      // Check for auto-save triggers after state update
      const shouldAutosave = (
        (nextScene?.backgroundImageUrl !== previousScene?.backgroundImageUrl) ||
        (nextScene?.backgroundKey !== previousScene?.backgroundKey) ||
        choice.startsQuest || choice.completesQuest ||
        nextScene?.startsQuest || nextScene?.completesQuest
      );
      if (shouldAutosave) {
        triggerAutosave();
      }
    },

    addCompanion: (companion: Companion) => set(state => ({ party: [...state.party, companion] })),

    saveGameToSlot: async (slotId) => {
      try {
        const state = get();
        if (!state.player) {
          console.error("Cannot save game without a player.");
          return false;
        }
        await db.gameSaves.put({ ...savableState(state), id: slotId, saveTimestamp: Date.now() });
        return true;
      } catch (error) {
        console.error(`Failed to save game to slot ${slotId}:`, error);
        return false;
      }
    },

    triggerAutosave: async () => {
        const { saveGameToSlot } = get();
        set({ autosaveNotificationVisible: true });
        await saveGameToSlot(1); // Always autosave to slot 1
        setTimeout(() => {
            set({ autosaveNotificationVisible: false });
        }, 3000);
    },

    unlockCampUpgrade: (upgradeId: string) => {
        set(state => {
            if (!state.player) return state;
            const upgrade = CAMP_UPGRADES.find(u => u.id === upgradeId);
            if (!upgrade) return state;

            const currentCopper = totalCurrencyInCopper(state.player.currency);
            const costInCopper = upgrade.cost * 100; // Assuming cost is in GP

            if (currentCopper < costInCopper) return state; // Should be checked by UI, but double check here

            const newCurrency = formatCurrencyFromCopper(currentCopper - costInCopper);
            const newUpgrades = [...state.campUpgrades, upgradeId];

            return {
                player: { ...state.player, currency: newCurrency },
                campUpgrades: newUpgrades,
            };
        });
    }
});

import { StateCreator } from 'zustand';
// FIX: The GameStore type is defined in `types.ts`, not exported from the store module. Corrected the import path.
import { GameStore, PlayerSlice, PlayerCharacter, Stat } from '../types';
import { audioManager } from '../services/audioService';
import { FEATS } from '../data/feats';
import { LYRA_PROGRESSION, VESPERA_PROGRESSION } from '../data/companions';

const getModifier = (statValue: number) => Math.floor((statValue - 10) / 2);

/**
 * Creates a slice of the store that manages all state and actions directly related to the player character.
 * This includes XP gain, leveling up, applying feats, and direct updates to the player object.
 * @param set - Zustand's `set` function.
 * @param get - Zustand's `get` function.
 * @returns An object containing the player-related state and actions.
 */
export const createPlayerSlice: StateCreator<GameStore, [], [], PlayerSlice> = (set, get) => ({
    updatePlayer: (playerUpdate) => {
      set(state => {
          if (!state.player) return state;
          const update = typeof playerUpdate === 'function' ? playerUpdate(state.player) : playerUpdate;
          return { player: { ...state.player, ...update } };
      });
    },

    gainXp: (amount) => {
        set(state => {
            if (!state.player) return state;
            const newPlayerXp = state.player.xp + amount;
            let isPlayerLevelUp = state.isLevelUpPending;
            if (newPlayerXp >= state.player.xpToNextLevel) {
                isPlayerLevelUp = true;
            }

            // Distribute XP to all party members
            const updatedParty = state.party.map(companion => {
                const newCompanionXp = companion.xp + amount;
                const companionXpToNextLevel = Math.floor(100 * Math.pow(companion.level, 1.5));

                // Check if this specific companion leveled up
                if (newCompanionXp >= companionXpToNextLevel) {
                    // Only trigger level up modal if one isn't already pending
                    // In a real app, we might want a queue, but for now first one wins
                    if (!state.companionLevelUpInfo) {
                        const newLevel = companion.level + 1;
                        let choices = [];

                        // Select progression based on ID
                        if (companion.id === 'lyra' && LYRA_PROGRESSION[newLevel]) {
                            choices = LYRA_PROGRESSION[newLevel].choices;
                        } else if (companion.id === 'vespera' && VESPERA_PROGRESSION[newLevel]) {
                            choices = VESPERA_PROGRESSION[newLevel].choices;
                        }

                        if (choices.length > 0) {
                            // Set pending level up state
                             // We don't update the companion object yet; wait for modal confirmation
                             set({ companionLevelUpInfo: {
                                companionId: companion.id,
                                level: newLevel,
                                choices: choices,
                            }});
                            return companion; // Return original companion, update happens in applyCompanionLevelUp
                        } else {
                            // Auto-level stats if no choices defined
                            const excessXp = newCompanionXp - companionXpToNextLevel;
                            return {
                                ...companion,
                                level: newLevel,
                                xp: excessXp,
                                stats: { ...companion.stats, maxHp: companion.stats.maxHp + 10, hp: companion.stats.maxHp + 10, dexterity: companion.stats.dexterity + 1, }
                            };
                        }
                    }
                }
                return { ...companion, xp: newCompanionXp };
            });

            return { player: { ...state.player, xp: newPlayerXp }, isLevelUpPending: isPlayerLevelUp, party: updatedParty };
        });
    },

    applyAutomaticLevelUp: () => {
        set(state => {
            if (!state.player || !state.isLevelUpPending) return state;
            audioManager.playSound('levelUp');

            let newPlayer = { ...state.player };
            const excessXp = newPlayer.xp - newPlayer.xpToNextLevel;
            newPlayer.level += 1;
            newPlayer.xp = excessXp;
            newPlayer.xpToNextLevel = Math.floor(100 * Math.pow(newPlayer.level, 1.5));

            const conModifier = getModifier(newPlayer.stats.constitution);
            const intModifier = getModifier(newPlayer.stats.intelligence);
            newPlayer.stats.maxHp += 10 + conModifier;
            newPlayer.stats.maxMana += 5 + intModifier;
            newPlayer.stats.hp = newPlayer.stats.maxHp;
            newPlayer.stats.mana = newPlayer.stats.maxMana;

            const primaryStat = newPlayer.characterClass.scalesWith?.[0] || 'strength';
            newPlayer.stats[primaryStat]++;

            return { player: newPlayer, isLevelUpPending: false };
        });
    },

    applyManualLevelUp: (choices) => {
        set(state => {
            if (!state.player || !state.isLevelUpPending) return state;
            audioManager.playSound('levelUp');

            let newPlayer = { ...state.player };
            const excessXp = newPlayer.xp - newPlayer.xpToNextLevel;
            newPlayer.level += 1;
            newPlayer.xp = excessXp;
            newPlayer.xpToNextLevel = Math.floor(100 * Math.pow(newPlayer.level, 1.5));

            const conModifier = getModifier(newPlayer.stats.constitution);
            const intModifier = getModifier(newPlayer.stats.intelligence);
            newPlayer.stats.maxHp += 10 + conModifier;
            newPlayer.stats.maxMana += 5 + intModifier;
            newPlayer.stats.hp = newPlayer.stats.maxHp;
            newPlayer.stats.mana = newPlayer.stats.maxMana;

            newPlayer.stats[choices.attribute]++;
            if (choices.featId) {
                newPlayer.feats = [...newPlayer.feats, choices.featId];
                const feat = FEATS[choices.featId];
                if (feat?.effects.stats) {
                    for (const [stat, value] of Object.entries(feat.effects.stats)) {
                         (newPlayer.stats as any)[stat] += value;
                    }
                }
            }

            return { player: newPlayer, isLevelUpPending: false };
        });
    },

    applyCompanionLevelUp: (abilityChoice) => {
        set(state => {
            if (!state.party.length || !state.companionLevelUpInfo) return state;

            const { companionId, level: newLevel } = state.companionLevelUpInfo;

            const updatedParty = state.party.map(c => {
                if (c.id !== companionId) return c;

                const companionXpToNextLevel = Math.floor(100 * Math.pow(c.level, 1.5));
                const excessXp = c.xp - companionXpToNextLevel;

                let newCompanion = { 
                    ...c, 
                    level: newLevel, 
                    xp: excessXp, 
                    stats: { 
                        ...c.stats, 
                        maxHp: c.stats.maxHp + 10, 
                        hp: c.stats.maxHp + 10, 
                        dexterity: c.stats.dexterity + 1, 
                        wisdom: c.stats.wisdom + (newLevel % 4 === 0 ? 1 : 0), 
                    } 
                };

                if (abilityChoice.type === 'spell') {
                    newCompanion.spells = [...newCompanion.spells, abilityChoice.id];
                } else {
                    newCompanion.martialAbilities = [...newCompanion.martialAbilities, abilityChoice.id];
                }
                return newCompanion;
            });

            return { party: updatedParty, companionLevelUpInfo: null };
        });
    },

    addFeat: (featId) => {
        set(state => {
            if (!state.player) return state;
            const newPlayer = { ...state.player };
            if (!newPlayer.feats.includes(featId)) {
                newPlayer.feats.push(featId);
            }
            return { player: newPlayer };
        });
    },
});

/**
 * @file combatSlice.ts
 * @description
 * This file contains the Zustand slice responsible for managing the state and logic of a combat encounter.
 * It encapsulates all functionality previously handled by the `CombatManager` class, adapting it to a
 * functional, state-driven pattern that is idiomatic to Zustand.
 *
 * The slice manages the entire lifecycle of a combat encounter, including:
 * - Starting combat and setting up combatants.
 * - Processing a queue of combat events in a turn-based manner.
 * - Handling player and AI actions.
 * - Calculating damage, healing, and status effects.
 * - Determining the outcome of the combat and applying rewards.
 * - Managing the transient UI state for player action selection.
 */
import { StateCreator } from 'zustand';
// FIX: The GameStore type is defined in `types.ts`, not exported from the store module. Corrected the import path.
import { 
    GameStore,
    CombatSlice, CombatState, Combatant, PlayerCharacter, Companion,
    Enemy, Ally, DamageType, CombatEvent, ActionDetails, Spell,
    MartialAbility, LogType, CombatLogEntry, StatusEffect,
    Item, PlayerActionState
} from '../types';
import { getEnemy, getAlly, getSpell, getItem } from '../services/dataService';
import { getAIAction } from '../services/aiService';
import { MARTIAL_ABILITIES } from '../data/martialAbilities';
import { ACTION_REGISTRY } from '../services/actionRegistry';
import { COMPANIONS } from '../data/companions';

const getModifier = (statValue: number) => Math.floor((statValue - 10) / 2);

const createLogEntry = (message: string, type: LogType, abilityId?: string): CombatLogEntry => ({
  id: `${Date.now()}-${Math.random()}`,
  message,
  type,
  abilityId,
});

export const createCombatSlice: StateCreator<GameStore, [], [], CombatSlice> = (set, get) => ({
    startCombat: (scene) => {
        const { player, party } = get();
        if (!player) return;

        const combatants: Combatant[] = [];
        const createCombatantFromPlayer = (p: PlayerCharacter): Combatant => ({
            id: 'player', originalId: 'player', name: p.name, spriteUrl: p.spriteUrl, type: 'player',
            maxHp: p.stats.maxHp, currentHp: p.stats.hp, maxMana: p.stats.maxMana, currentMana: p.stats.mana,
            maxStamina: p.stats.maxStamina, currentStamina: p.stats.stamina,
            speed: p.stats.dexterity, armorClass: 10 + getModifier(p.stats.dexterity), // simplified AC
            attackBonus: 4 + getModifier(p.stats[p.characterClass.scalesWith?.[0] || 'strength']),
            damage: p.equipment.mainHand?.damage || { amount: 1 + getModifier(p.stats.strength), type: DamageType.BLUDGEONING },
            isDefeated: false, statusEffects: [],
            martialAbilities: p.martialAbilities, spells: p.spells,
        });

        const createCombatantFromCompanion = (c: Companion): Combatant => ({
            id: c.id, originalId: c.id, name: c.name, spriteUrl: c.spriteUrl, type: 'companion',
            maxHp: c.stats.maxHp, currentHp: c.stats.hp, maxStamina: c.stats.maxStamina, currentStamina: c.stats.stamina,
            speed: c.stats.dexterity, armorClass: 10 + getModifier(c.stats.dexterity),
            attackBonus: 3 + getModifier(c.stats[COMPANIONS[c.id].characterClass === 'Ranger' ? 'dexterity' : 'strength']),
            damage: c.equipment.mainHand?.damage || { amount: 1 + getModifier(c.stats.strength), type: DamageType.BLUDGEONING },
            isDefeated: false, statusEffects: [],
            martialAbilities: c.martialAbilities, spells: c.spells, personality: c.personality,
        });

        const createCombatantFromEnemy = (e: Enemy, uniqueId: string): Combatant => ({
            id: uniqueId, originalId: e.id, name: e.name, spriteUrl: e.imageUrl, type: 'enemy',
            maxHp: e.stats.maxHp, currentHp: e.stats.maxHp, maxMana: e.stats.maxMana, currentMana: e.stats.maxMana,
            maxStamina: e.stats.maxStamina, currentStamina: e.stats.maxStamina,
            speed: e.stats.speed, armorClass: e.stats.armorClass, attackBonus: e.stats.attackBonus, damage: e.stats.damage,
            isDefeated: false, statusEffects: [],
            martialAbilities: e.stats.martialAbilities, personality: e.stats.personality,
        });

        const createCombatantFromAlly = (a: Ally, uniqueId: string): Combatant => ({
            id: uniqueId, originalId: a.id, name: a.name, spriteUrl: a.imageUrl, type: 'companion',
            maxHp: a.stats.maxHp, currentHp: a.stats.maxHp, maxStamina: a.stats.maxStamina, currentStamina: a.stats.maxStamina,
            speed: a.stats.speed, armorClass: a.stats.armorClass, attackBonus: a.stats.attackBonus, damage: a.stats.damage,
            isDefeated: false, statusEffects: [],
            martialAbilities: a.stats.martialAbilities, personality: a.stats.personality,
        });

        combatants.push(createCombatantFromPlayer(player));

        // Add all party members to combat
        party.forEach(companion => {
            combatants.push(createCombatantFromCompanion(companion));
        });

        scene.enemies.forEach(({ enemyId, count }) => {
            const enemyData = getEnemy(enemyId);
            if (enemyData) for (let i = 0; i < count; i++) combatants.push(createCombatantFromEnemy(enemyData, `${enemyId}_${i}`));
        });
        scene.temporaryCompanions?.forEach(({ allyId, count }) => {
            const allyData = getAlly(allyId);
            if (allyData) for (let i = 0; i < count; i++) combatants.push(createCombatantFromAlly(allyData, `${allyId}_${i}`));
        });

        const turnOrder = [...combatants].sort((a, b) => b.speed - a.speed).map(c => c.id);
        const initialCombatState: CombatState = {
            combatants, turnOrder, currentTurnId: turnOrder[0], isProcessingEvent: false, eventQueue: [],
            log: [createLogEntry('Combat begins!', 'system')],
            onVictoryScene: scene.onVictoryScene, onDefeatScene: scene.onDefeatScene,
            isFinished: null, rewards: null,
            playerActionState: { type: null, isAwaitingTarget: false },
        };
        const firstEvent: CombatEvent = { type: 'TURN_START', combatantId: turnOrder[0] };

        set({ combatState: { ...initialCombatState, eventQueue: [firstEvent] } });
    },

    setPlayerAction: (action) => {
        set(state => {
            if (!state.combatState) return state;
            return {
                combatState: {
                    ...state.combatState,
                    playerActionState: action,
                }
            };
        });
    },

    playerChooseAction: (action, targetId) => {
        const { combatState } = get();
        if (!combatState || combatState.currentTurnId !== 'player') return;
        const addCombatEvent = (event: CombatEvent, atStart = false) => {
            set(state => {
                if (!state.combatState) return state;
                const newQueue = atStart ? [event, ...state.combatState.eventQueue] : [...state.combatState.eventQueue, event];
                return { combatState: { ...state.combatState, eventQueue: newQueue } };
            });
        };
        addCombatEvent({ type: 'ACTION_CHOSEN', sourceId: 'player', targetId, action });
    },

    processNextCombatEvent: async () => {
        const { combatState } = get();
        if (!combatState || combatState.isProcessingEvent || combatState.eventQueue.length === 0) return;

        set(state => ({ combatState: { ...state.combatState!, isProcessingEvent: true } }));

        const event = get().combatState!.eventQueue[0];
        set(state => ({ combatState: { ...state.combatState!, eventQueue: state.combatState!.eventQueue.slice(1) }}));

        let newEvents: CombatEvent[] = [];
        const currentCombatState = get().combatState!;

        const addCombatEvent = (event: CombatEvent, atStart = false) => {
            if (atStart) newEvents.unshift(event);
            else newEvents.push(event);
        };

        switch (event.type) {
            case 'TURN_START': {
                const combatant = currentCombatState.combatants.find(c => c.id === event.combatantId)!;
                addCombatEvent({ type: 'LOG_MESSAGE', message: `${combatant.name}'s turn.`, logType: 'system' });

                if (combatant.statusEffects.some(e => e.type === 'STUNNED')) {
                    addCombatEvent({ type: 'LOG_MESSAGE', message: `${combatant.name} is stunned!`, logType: 'info' });
                    addCombatEvent({ type: 'TURN_END', combatantId: combatant.id });
                } else if (combatant.type !== 'player') {
                    const aiAction = await getAIAction(combatant, currentCombatState);
                    if (aiAction.type === 'idle') {
                        addCombatEvent({ type: 'LOG_MESSAGE', message: `${combatant.name} hesitates.`, logType: 'info' });
                        addCombatEvent({ type: 'TURN_END', combatantId: combatant.id });
                    } else {
                        const { targetId, ...actionDetails } = aiAction;
                        addCombatEvent({ type: 'ACTION_CHOSEN', sourceId: combatant.id, targetId: targetId, action: actionDetails });
                    }
                }
                break;
            }
            case 'ACTION_CHOSEN': {
                const { sourceId, targetId, action } = event;
                const source = currentCombatState.combatants.find(c => c.id === sourceId)!;
                const target = currentCombatState.combatants.find(c => c.id === targetId)!;
                let actionId: string | undefined;

                if (action.type === 'attack') actionId = 'basic-attack';
                else if (action.type === 'spell') {
                    const spellData = await getSpell(action.spellSlug!);
                    if (spellData && source.currentMana! >= spellData.manaCost) {
                        set(state => ({ combatState: { ...state.combatState!, combatants: state.combatState!.combatants.map(c => c.id === sourceId ? { ...c, currentMana: c.currentMana! - spellData.manaCost } : c) } }));
                        actionId = spellData.actionId;
                    } else addCombatEvent({ type: 'LOG_MESSAGE', message: `${source.name} does not have enough mana.`, logType: 'info' });
                } else if (action.type === 'ability') {
                    const abilityData = MARTIAL_ABILITIES[action.abilityId!];
                    if (abilityData && source.currentStamina! >= abilityData.staminaCost) {
                        set(state => ({ combatState: { ...state.combatState!, combatants: state.combatState!.combatants.map(c => c.id === sourceId ? { ...c, currentStamina: c.currentStamina! - abilityData.staminaCost } : c) } }));
                        actionId = abilityData.actionId;
                    } else addCombatEvent({ type: 'LOG_MESSAGE', message: `${source.name} does not have enough stamina.`, logType: 'info' });
                }

                if (actionId && ACTION_REGISTRY[actionId]) {
                    const generatedEvents = ACTION_REGISTRY[actionId].resolve(source, target, currentCombatState.combatants);
                    newEvents.push(...generatedEvents);
                }
                addCombatEvent({ type: 'TURN_END', combatantId: sourceId });
                break;
            }
             case 'ATTACK_RESOLVED': {
                if (event.hit) {
                    const abilityName = event.abilityId ? (MARTIAL_ABILITIES[event.abilityId]?.name || (await getSpell(event.abilityId))?.name || event.abilityId) : '';
                    const sourceName = currentCombatState.combatants.find(c=>c.id === event.sourceId)?.name || 'Unknown';
                    const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';

                    const message = `${sourceName} ${abilityName ? `uses ${abilityName} and ` : ''}hits ${targetName} for ${event.damage} ${event.damageType} damage.`;
                    addCombatEvent({ type: 'LOG_MESSAGE', message, logType: 'damage' });

                    let targetDefeated = false;
                    set(state => {
                        const newCombatants = state.combatState!.combatants.map(c => {
                            if (c.id === event.targetId) {
                                const newHp = Math.max(0, c.currentHp - event.damage);
                                if (newHp <= 0) targetDefeated = true;
                                return {...c, currentHp: newHp};
                            }
                            return c;
                        });
                        return { combatState: {...state.combatState!, combatants: newCombatants}};
                    });
                    if (targetDefeated) addCombatEvent({ type: 'COMBATANT_DEFEATED', combatantId: event.targetId });
                } else {
                     const sourceName = currentCombatState.combatants.find(c=>c.id === event.sourceId)?.name || 'Unknown';
                     const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';
                    addCombatEvent({ type: 'LOG_MESSAGE', message: `${sourceName} misses ${targetName}.`, logType: 'miss' });
                }
                break;
            }
            case 'HEAL_RESOLVED': {
                 const sourceName = currentCombatState.combatants.find(c=>c.id === event.sourceId)?.name || 'Unknown';
                 const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';
                 addCombatEvent({ type: 'LOG_MESSAGE', message: `${sourceName} heals ${targetName} for ${event.amount} HP.`, logType: 'heal' });
                 set(state => {
                     const newCombatants = state.combatState!.combatants.map(c => c.id === event.targetId ? {...c, currentHp: Math.min(c.maxHp, c.currentHp + event.amount)} : c);
                     return { combatState: {...state.combatState!, combatants: newCombatants}};
                 });
                 break;
            }
            case 'STATUS_APPLIED': {
                 const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';
                 addCombatEvent({ type: 'LOG_MESSAGE', message: `${targetName} is now ${event.effect.name}.`, logType: 'status' });
                 set(state => {
                     const newCombatants = state.combatState!.combatants.map(c => c.id === event.targetId ? {...c, statusEffects: [...c.statusEffects, event.effect]} : c);
                     return { combatState: {...state.combatState!, combatants: newCombatants}};
                 });
                 break;
            }
            case 'COMBATANT_DEFEATED': {
                const defeatedName = currentCombatState.combatants.find(c=>c.id === event.combatantId)?.name || 'Unknown';
                addCombatEvent({ type: 'LOG_MESSAGE', message: `${defeatedName} has been defeated!`, logType: 'system' });

                let partyAlive = false;
                let enemiesAlive = false;
                set(state => {
                     const newCombatants = state.combatState!.combatants.map(c => c.id === event.combatantId ? {...c, isDefeated: true, currentHp: 0} : c);
                     partyAlive = newCombatants.some(c => (c.type === 'player' || c.type === 'companion') && !c.isDefeated);
                     enemiesAlive = newCombatants.some(c => c.type === 'enemy' && !c.isDefeated);
                     return { combatState: {...state.combatState!, combatants: newCombatants}};
                 });

                if (!partyAlive) addCombatEvent({ type: 'COMBAT_END', outcome: 'defeat' }, true);
                else if (!enemiesAlive) addCombatEvent({ type: 'COMBAT_END', outcome: 'victory' }, true);

                break;
            }
            case 'TURN_END': {
                const combatant = currentCombatState.combatants.find(c => c.id === event.combatantId)!;
                const updatedEffects = combatant.statusEffects
                    .map(effect => ({ ...effect, duration: effect.duration - 1 }))
                    .filter(effect => {
                        if (effect.duration <= 0) {
                            addCombatEvent({ type: 'LOG_MESSAGE', message: `${effect.name} has worn off for ${combatant.name}.`, logType: 'status' });
                            return false;
                        }
                        return true;
                    });
                set(state => ({ combatState: { ...state.combatState!, combatants: state.combatState!.combatants.map(c => c.id === event.combatantId ? {...c, statusEffects: updatedEffects} : c) }}));

                const turnOrder = currentCombatState.turnOrder;
                const currentIndex = turnOrder.indexOf(event.combatantId);
                let nextIndex = (currentIndex + 1) % turnOrder.length;
                let nextCombatant = get().combatState!.combatants.find(c => c.id === turnOrder[nextIndex])!;

                while (nextCombatant.isDefeated) {
                    nextIndex = (nextIndex + 1) % turnOrder.length;
                    nextCombatant = get().combatState!.combatants.find(c => c.id === turnOrder[nextIndex])!;
                }

                addCombatEvent({ type: 'TURN_START', combatantId: nextCombatant.id }, true);
                set(state => ({ combatState: {...state.combatState!, currentTurnId: nextCombatant.id }}));
                break;
            }
            case 'COMBAT_END': {
                if (event.outcome === 'victory') {
                    const defeatedEnemies = currentCombatState.combatants.filter(c => c.type === 'enemy' && c.isDefeated && c.originalId);
                    const xp = defeatedEnemies.reduce((total, c) => total + (getEnemy(c.originalId!)?.stats.xpValue || 0), 0);

                    const lootPromises = defeatedEnemies.flatMap(c => {
                        const enemyData = getEnemy(c.originalId!);
                        return enemyData?.stats.lootTable?.map(async (lootItem) => {
                            if (Math.random() < lootItem.dropChance) {
                                const item = await getItem(lootItem.itemId);
                                if (item) {
                                    return { item, quantity: 1 };
                                }
                            }
                            return null;
                        }) || [];
                    });

                    const resolvedLoot = (await Promise.all(lootPromises)).filter((l): l is { item: Item, quantity: number } => l !== null);

                    const consolidatedLoot = resolvedLoot.reduce((acc, drop) => {
                        const existing = acc.find(l => l.item.id === drop.item.id);
                        if (existing) {
                            existing.quantity += drop.quantity;
                        } else {
                            acc.push(drop);
                        }
                        return acc;
                    }, [] as { item: Item, quantity: number }[]);

                    set(state => ({ combatState: {...state.combatState!, isFinished: event.outcome, rewards: { xp, loot: consolidatedLoot } }}));
                } else {
                    set(state => ({ combatState: {...state.combatState!, isFinished: event.outcome, rewards: null }}));
                }
                break;
            }
            case 'LOG_MESSAGE': {
                 set(state => ({ combatState: {...state.combatState!, log: [...state.combatState!.log, createLogEntry(event.message, event.logType)] }}));
                break;
            }
        }

        set(state => {
            if (!state.combatState) return state;
            const newQueue = [...newEvents, ...state.combatState.eventQueue];
            return { combatState: { ...state.combatState, eventQueue: newQueue, isProcessingEvent: false } };
        });
    },

    concludeCombat: () => {
        const { combatState, player, gainXp, addItemsToPlayerInventory, advanceScene, triggerAutosave } = get();
        if (!combatState || !combatState.isFinished) return;

        if (combatState.isFinished === 'victory' && combatState.rewards) {
            gainXp(combatState.rewards.xp);
            if (combatState.rewards.loot.length > 0) {
                addItemsToPlayerInventory(combatState.rewards.loot);
            }
        }

        const newPlayerStats = { ...player!.stats };
        const playerInCombat = combatState.combatants.find(c => c.id === 'player');
        if (playerInCombat) {
            newPlayerStats.hp = playerInCombat.currentHp;
            newPlayerStats.mana = playerInCombat.currentMana!;
        }

        const sceneId = combatState.isFinished === 'victory' ? combatState.onVictoryScene : combatState.onDefeatScene;

        set({ combatState: null });

        // Trigger autosave before advancing scene
        triggerAutosave().then(() => {
            advanceScene({ text: 'Combat Ends', nextScene: sceneId });
        });
    },
});

/**
 * @file effectRegistry.ts
 * @description
 * This file serves as a centralized registry for all game logic effects that can be triggered
 * by scenes or player choices. By decoupling logic from the data in `data/scenes.ts`,
 * we achieve several key benefits:
 * 1.  **Data Purity:** Scene and choice data becomes pure, serializable (like JSON), which is
 *     essential for a robust save/load system.
 * 2.  **Modularity & Reusability:** Effects can be easily reused across multiple scenes or choices
 *     without duplicating code.
 * 3.  **Testability:** Each effect function can be individually imported and unit-tested
 *     in isolation.
 * 4.  **Maintainability:** All game logic is consolidated in one place, making it easier to
 *     find, modify, and debug.
 *
 * The `EFFECT_REGISTRY` object maps a unique string identifier (e.g., 'ADD_HEALING_POTION_TO_INVENTORY')
 * to a function that takes the current `GameState` and returns the modified `GameState`.
 * The game engine (`store/gameSlice.ts`) uses this registry to execute effects based on the
 * `effectId` property in scene or choice objects.
 */

import { GameState } from '../types';
import { ITEMS } from '../data/items';
import { COMPANIONS } from '../data/companions';
import { NPCS } from '../data/npcs';
import { addItemToInventory, formatCurrencyFromCopper, totalCurrencyInCopper, updateInventoryByQuantity } from '../lib/utils';
import { FACTIONS } from '../data/factions';

type EffectFunction = (gameState: GameState) => GameState;

export const EFFECT_REGISTRY: Record<string, EffectFunction> = {
    SET_PLAYER_CURRENCY_TO_ZERO: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player, currency: { gp: 0, sp: 0, cp: 0 } };
        return { ...gameState, player: newPlayer };
    },
    ADD_HEALING_POTION_TO_INVENTORY: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: finalInventory } = addItemToInventory(gameState.player.inventory, ITEMS['potion-of-healing']);
        const newPlayer = { ...gameState.player, inventory: finalInventory };
        return { ...gameState, player: newPlayer };
    },
    RECEIVE_FINNS_COIN: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: finalInventory } = addItemToInventory(gameState.player.inventory, ITEMS['finns-wooden-coin']);
        const newPlayer = { ...gameState.player, inventory: finalInventory };
        const newFlags = { ...gameState.globalFlags, talkedToFinnAfterRats: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    RECEIVE_BARKEEP_REWARD_BASIC: (gameState) => {
        if (!gameState.player) return gameState;
        let currentInventory = gameState.player.inventory;
        const { inventory: inventoryAfterSword } = addItemToInventory(currentInventory, ITEMS['rusty-sword']);
        const { inventory: finalInventory } = addItemToInventory(inventoryAfterSword, ITEMS['leather-armor']);
        const newPlayer = { ...gameState.player, inventory: finalInventory };
        const newFlags = { ...gameState.globalFlags, hasTavernRoom: true, completed_rat_extermination: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    RECEIVE_BARKEEP_REWARD_SOLDIER: (gameState) => {
        if (!gameState.player) return gameState;
        let currentInventory = gameState.player.inventory;
        const { inventory: inventoryAfterSword } = addItemToInventory(currentInventory, ITEMS['longsword-of-the-legion']);
        const { inventory: finalInventory } = addItemToInventory(inventoryAfterSword, ITEMS['leather-armor']);
        const newPlayer = { ...gameState.player, inventory: finalInventory };
        const newFlags = { ...gameState.globalFlags, hasTavernRoom: true, completed_rat_extermination: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    FIND_MILL_CACHE: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: newInventory } = addItemToInventory(gameState.player.inventory, ITEMS['fine-dagger']);
        const currentTotal = totalCurrencyInCopper(gameState.player.currency);
        const newCurrency = formatCurrencyFromCopper(currentTotal + 2000); // 20 gold
        const newPlayer = { ...gameState.player, inventory: newInventory, currency: newCurrency };
        return { ...gameState, player: newPlayer };
    },
    REST_AND_RESET_DAILIES: (gameState) => {
        if (!gameState.player) return gameState;

        const hasKitchen = gameState.campUpgrades.includes('field_kitchen');
        const hasInfirmary = gameState.campUpgrades.includes('infirmary');
        const hasTraining = gameState.campUpgrades.includes('training_grounds');

        // Base HP restoration is 50% max HP, unless Infirmary is built (100%)
        const healRatio = hasInfirmary ? 1.0 : 0.5;
        const hpToRestore = Math.floor(gameState.player.stats.maxHp * healRatio);

        const currentHp = Math.min(gameState.player.stats.maxHp, gameState.player.stats.hp + hpToRestore);

        const newPlayer = {
            ...gameState.player,
            xp: hasTraining ? gameState.player.xp + 50 : gameState.player.xp,
            stats: {
                ...gameState.player.stats,
                hp: currentHp,
                mana: gameState.player.stats.maxMana,
                stamina: gameState.player.stats.maxStamina,
            },
        };
        const newCounters = { ...gameState.actionCounters, performed_today: 0 };
        return { ...gameState, player: newPlayer, actionCounters: newCounters };
    },
    MEET_HERALD: (gameState) => {
        const newGameState = { ...gameState, globalFlags: { ...gameState.globalFlags, metHerald: true } };
        if (!newGameState.player) return newGameState;
        const { inventory: newInventory } = addItemToInventory(newGameState.player.inventory, ITEMS['ornate-key']);
        const newPlayer = { ...newGameState.player, inventory: newInventory };
        newPlayer.currency.gp = (newPlayer.currency.gp || 0) + 25;
        newGameState.player = newPlayer;
        return newGameState;
    },
    PERFORM_FOR_COIN: (gameState) => {
        if (!gameState.player) return gameState;
        const currentTotal = totalCurrencyInCopper(gameState.player.currency);
        const newCurrency = formatCurrencyFromCopper(currentTotal + 500); // 5 gold
        const newPlayer = { ...gameState.player, currency: newCurrency };
        const newCounters = { ...gameState.actionCounters, performed_today: 1 };
        return { ...gameState, player: newPlayer, actionCounters: newCounters };
    },
    IMPRESS_XYLOS_NOBLE: (gameState) => {
        const newFlags = { ...gameState.globalFlags, xylos_discount: true };
        const newNpcState = JSON.parse(JSON.stringify(gameState.npcState));
        if (!newNpcState['xylos_merchant']) {
            const npcData = NPCS['xylos_merchant'];
            newNpcState['xylos_merchant'] = {
                inventory: JSON.parse(JSON.stringify(npcData.inventory)),
                attitude: npcData.attitude || 0,
            };
        }
        newNpcState['xylos_merchant'].attitude = (newNpcState['xylos_merchant'].attitude || 0) + 20;
        return { ...gameState, globalFlags: newFlags, npcState: newNpcState };
    },
    FLAG_CRYPT_DOOR_OPENED: (gameState) => {
        const newFlags = { ...gameState.globalFlags, cryptDoorOpened: true };
        return { ...gameState, globalFlags: newFlags };
    },
    FLAG_VISITED_CRYPT_ENTRANCE: (gameState) => ({ ...gameState, globalFlags: { ...gameState.globalFlags, visitedCryptEntrance: true } }),
    LYRA_JOINS_PARTY: (gameState) => {
        if (gameState.party.some(c => c.id === 'lyra')) return gameState;
        const newCompanion = COMPANIONS['lyra'];
        const newPlayer = gameState.player ? { ...gameState.player, xp: gameState.player.xp + 50 } : null;
        const newFlags = { ...gameState.globalFlags, metLyra: true };
        return { ...gameState, party: [...gameState.party, newCompanion], player: newPlayer, globalFlags: newFlags };
    },
    DECLINE_LYRA: (gameState) => ({ ...gameState, globalFlags: { ...gameState.globalFlags, declinedCompanion: true, metLyra: true } }),
    LYRA_OUTLANDER_REMARK: (gameState) => {
        if (!gameState.player) return gameState;
        // Increase affinity for Lyra if she is in party
        const newParty = gameState.party.map(c => {
            if (c.id === 'lyra') {
                return { ...c, affinity: Math.min(100, c.affinity + 10) };
            }
            return c;
        });

        const { inventory: newInventory } = addItemToInventory(gameState.player.inventory, ITEMS['trackers-unguent']);
        const newPlayer = { ...gameState.player, inventory: newInventory };
        const newFlags = { ...gameState.globalFlags, lyra_outlander_remark_done: true };
        return { ...gameState, player: newPlayer, party: newParty, globalFlags: newFlags };
    },
    LYRA_AFFINITY_PLUS_20: (gameState) => {
        const newParty = gameState.party.map(c => {
            if (c.id === 'lyra') {
                return { ...c, affinity: Math.min(100, c.affinity + 20) };
            }
            return c;
        });
        return { ...gameState, party: newParty };
    },
    LYRA_AFFINITY_PLUS_10: (gameState) => {
        const newParty = gameState.party.map(c => {
            if (c.id === 'lyra') {
                return { ...c, affinity: Math.min(100, c.affinity + 10) };
            }
            return c;
        });
        return { ...gameState, party: newParty };
    },
    FLAG_TOLD_BARKEEP_ABOUT_CRYPT: (gameState) => ({ ...gameState, globalFlags: { ...gameState.globalFlags, toldBarkeepAboutCrypt: true } }),
    FLAG_ASKED_QUEEN_WHO: (gameState) => ({ ...gameState, globalFlags: { ...gameState.globalFlags, askedQueenWho: true } }),
    FLAG_ASKED_QUEEN_WHY: (gameState) => ({ ...gameState, globalFlags: { ...gameState.globalFlags, askedQueenWhy: true } }),
    FLAG_ASKED_QUEEN_BETRAYER: (gameState) => ({ ...gameState, globalFlags: { ...gameState.globalFlags, askedAboutBetrayer: true } }),
    FLAG_ASKED_QUEEN_WHAT: (gameState) => ({ ...gameState, globalFlags: { ...gameState.globalFlags, askedQueenWhat: true } }),
    ACCEPT_DESTINY: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: finalInventory } = addItemToInventory(gameState.player.inventory, ITEMS['serpents-eye-amulet']);
        const newPlayer = { 
            ...gameState.player, 
            xp: gameState.player.xp + 200,
            inventory: finalInventory,
        };
        const newFlags = { ...gameState.globalFlags, destinyChosen: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    REFUSE_DESTINY: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player, karma: gameState.player.karma - 5 };
        const newFlags = { ...gameState.globalFlags, destinyChosen: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    RECEIVE_ACOLYTE_GIFT: (gameState) => {
        if (!gameState.player) return gameState;
        let inv = gameState.player.inventory;
        inv = addItemToInventory(inv, ITEMS['potion-of-healing']).inventory;
        inv = addItemToInventory(inv, ITEMS['potion-of-healing']).inventory;
        const newPlayer = { ...gameState.player, inventory: inv };
        const newFlags = { ...gameState.globalFlags, receivedAcolyteGift: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    DONATE_GOLD_KARMA_PLUS_5: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player };
        const total = totalCurrencyInCopper(newPlayer.currency);
        newPlayer.currency = formatCurrencyFromCopper(total - 100);
        newPlayer.karma += 5;
        return { ...gameState, player: newPlayer };
    },
    DONATE_SILVER_KARMA_PLUS_3: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player };
        const total = totalCurrencyInCopper(newPlayer.currency);
        newPlayer.currency = formatCurrencyFromCopper(total - 50);
        newPlayer.karma += 3;
        return { ...gameState, player: newPlayer };
    },
    DONATE_COPPER_KARMA_PLUS_1: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player };
        const total = totalCurrencyInCopper(newPlayer.currency);
        newPlayer.currency = formatCurrencyFromCopper(total - 10);
        newPlayer.karma += 1;
        return { ...gameState, player: newPlayer };
    },
    ACCEPT_ELARA_QUEST: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: newInventory } = addItemToInventory(gameState.player.inventory, ITEMS['mariners-guild-seal']);
        const newPlayer = { ...gameState.player, inventory: newInventory };
        return { ...gameState, player: newPlayer };
    },
    ACCEPT_ELARA_QUEST_SAILOR: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: newInventory } = addItemToInventory(gameState.player.inventory, ITEMS['mariners-guild-seal']);
        const currentTotal = totalCurrencyInCopper(gameState.player.currency);
        const newCurrency = formatCurrencyFromCopper(currentTotal + 2500); // 25 gold
        const newPlayer = { ...gameState.player, inventory: newInventory, currency: newCurrency };
        return { ...gameState, player: newPlayer };
    },
    ACCEPT_SYNDICATE_QUEST_KARMA_MINUS_2: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player, karma: gameState.player.karma - 2 };
        return { ...gameState, player: newPlayer };
    },
    ACCEPT_SYNDICATE_QUEST_INSIDER: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player, karma: gameState.player.karma - 2 };
        const newFlags = { ...gameState.globalFlags, syndicateInsiderDeal: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    ACCEPT_SYNDICATE_QUEST_CHARLATAN: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player, karma: gameState.player.karma - 2 };
        const newFlags = { ...gameState.globalFlags, syndicate_knows_plot: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    FORGE_ALLIANCE_STONECARVERS_CRIMSONBLADES: (gameState) => {
        const newOverrides = JSON.parse(JSON.stringify(gameState.factionRelationsOverrides || {}));

        const addAlly = (factionId: string, allyId: string) => {
            if (!newOverrides[factionId]) newOverrides[factionId] = {};
            if (!newOverrides[factionId].allies) {
                newOverrides[factionId].allies = FACTIONS.find(f => f.id === factionId)?.relations?.allies?.slice() || [];
            }
            if (!newOverrides[factionId].allies.includes(allyId)) {
                newOverrides[factionId].allies.push(allyId);
            }
        };

        addAlly('stonecarvers_guild', 'crimson_blades');
        addAlly('crimson_blades', 'stonecarvers_guild');

        return { ...gameState, factionRelationsOverrides: newOverrides };
    },
    BREAK_ALLIANCE_MARINERS_STONECARVERS: (gameState) => {
        const newOverrides = JSON.parse(JSON.stringify(gameState.factionRelationsOverrides || {}));

        const removeAlly = (factionId: string, allyIdToRemove: string) => {
            if (!newOverrides[factionId]) newOverrides[factionId] = {};
            if (newOverrides[factionId].allies) {
                newOverrides[factionId].allies = newOverrides[factionId].allies.filter((ally: string) => ally !== allyIdToRemove);
            } else {
                const staticAllies = FACTIONS.find(f => f.id === factionId)?.relations?.allies?.slice() || [];
                newOverrides[factionId].allies = staticAllies.filter((ally: string) => ally !== allyIdToRemove);
            }
        };

        removeAlly('mariners_guild', 'stonecarvers_guild');
        removeAlly('stonecarvers_guild', 'mariners_guild');

        return { ...gameState, factionRelationsOverrides: newOverrides };
    },
    JOIN_CRIMSON_BLADES: (gameState) => {
        if (!gameState.player) return gameState;
        const newPlayer = { ...gameState.player, factionId: 'crimson_blades', reputation: { ...gameState.player.reputation, 'crimson_blades': (gameState.player.reputation['crimson_blades'] || 0) + 15 } };
        const newFlags = { ...gameState.globalFlags, joined_crimson_blades: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    COMPLETE_BROMS_BANNER: (gameState) => {
        if (!gameState.player) return gameState;

        const { inventory: newInventory } = updateInventoryByQuantity(gameState.player.inventory, ITEMS['crimson-blades-banner'], -1);

        const currentTotal = totalCurrencyInCopper(gameState.player.currency);
        const newCurrency = formatCurrencyFromCopper(currentTotal + 5000); // 50 gold

        const newPlayer = { 
            ...gameState.player, 
            inventory: newInventory,
            currency: newCurrency, 
            reputation: { ...gameState.player.reputation, 'crimson_blades': (gameState.player.reputation['crimson_blades'] || 0) + 10 }
        };
        const newFlags = { ...gameState.globalFlags, completed_broms_banner: true };

        let newQuests = { ...gameState.quests };
        if (newQuests['broms_banner_known_past']) newQuests['broms_banner_known_past'].status = 'completed';
        if (newQuests['broms_banner_unknown_past']) newQuests['broms_banner_unknown_past'].status = 'completed';


        return { ...gameState, player: newPlayer, globalFlags: newFlags, quests: newQuests };
    },
    COMPLETE_BORIN_QUEST: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: inventoryAfterHead } = updateInventoryByQuantity(gameState.player.inventory, ITEMS['goblin-leader-head'], -1);
        const { inventory: finalInventory } = addItemToInventory(inventoryAfterHead, ITEMS['aegis-of-the-devout']);

        const currentTotal = totalCurrencyInCopper(gameState.player.currency);
        const newCurrency = formatCurrencyFromCopper(currentTotal + 10000); // 100 gold

        const newPlayer = { ...gameState.player, inventory: finalInventory, currency: newCurrency };
        return { ...gameState, player: newPlayer };
    },
    COMPLETE_XYLOS_QUEST: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: inventoryAfterFlower } = updateInventoryByQuantity(gameState.player.inventory, ITEMS['moonpetal-flower'], -1);
        const { inventory: finalInventory } = addItemToInventory(inventoryAfterFlower, ITEMS['tome-of-clear-thought']);

        const currentTotal = totalCurrencyInCopper(gameState.player.currency);
        const newCurrency = formatCurrencyFromCopper(currentTotal + 5000); // 50 gold (example)

        const newPlayer = { ...gameState.player, inventory: finalInventory, currency: newCurrency };
        return { ...gameState, player: newPlayer };
    },
    BROM_GIVES_OLD_AMULET: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: finalInventory } = addItemToInventory(gameState.player.inventory, ITEMS['broms_veteran_amulet']);
        const newPlayer = { ...gameState.player, inventory: finalInventory };
        const newFlags = { ...gameState.globalFlags, received_broms_amulet: true };
        return { ...gameState, player: newPlayer, globalFlags: newFlags };
    },
    FLAG_MET_VORLAG: (gameState) => {
        return { ...gameState, globalFlags: { ...gameState.globalFlags, met_vorlag: true } };
    },
    FLAG_KNOWS_BROMS_PAST: (gameState) => {
        return { ...gameState, globalFlags: { ...gameState.globalFlags, knows_broms_past: true } };
    },
    FLAG_DECLINED_GOBLIN_QUEST: (gameState) => {
      return {...gameState, globalFlags: {...gameState.globalFlags, declinedGoblinQuest: true}}
    },
    FLAG_LYRA_RESCUE_REVEALED: (gameState) => {
        return {...gameState, globalFlags: {...gameState.globalFlags, lyraRescueRevealed: true}}
    },
    GET_CRIMSON_BLADES_BANNER: (gameState) => {
        if (!gameState.player) return gameState;
        const { inventory: finalInventory } = addItemToInventory(gameState.player.inventory, ITEMS['crimson-blades-banner']);
        const newPlayer = { ...gameState.player, inventory: finalInventory };
        return { ...gameState, player: newPlayer };
    },
    MEET_SCAVENGER: (gameState) => {
        const newFlags = { ...gameState.globalFlags, met_scavenger: true };
        return { ...gameState, globalFlags: newFlags };
    },
    SCAVENGER_DEFEATED: (gameState) => {
        if (!gameState.player) return gameState;
        const newRep = { ...gameState.player.reputation, 'crimson_blades': (gameState.player.reputation['crimson_blades'] || 0) + 10 };
        const newPlayer = { ...gameState.player, reputation: newRep };
        return { ...gameState, player: newPlayer };
    },
    RECRUIT_KORGAN: (gameState) => {
        const newFlags = { ...gameState.globalFlags, recruited_korgan: true };
        return { ...gameState, globalFlags: newFlags };
    },
    RECRUIT_ELARA: (gameState) => {
        const newFlags = { ...gameState.globalFlags, recruited_elara: true };
        return { ...gameState, globalFlags: newFlags };
    },
    RECRUIT_VESPERA: (gameState) => {
        // Prevent duplicate recruitment
        if (gameState.party.some(c => c.id === 'vespera')) return gameState;
        const newCompanion = COMPANIONS['vespera'];
        const newFlags = { ...gameState.globalFlags, recruited_vespera: true, met_vespera: true };
        const newPlayer = gameState.player ? { ...gameState.player, xp: gameState.player.xp + 100 } : null; // XP Bonus
        return { ...gameState, party: [...gameState.party, newCompanion], player: newPlayer, globalFlags: newFlags };
    },
    VESPERA_LEAVES_HOSTILE: (gameState) => {
        const newFlags = { ...gameState.globalFlags, met_vespera: true };
        return { ...gameState, globalFlags: newFlags };
    }
};

import React, { useMemo } from 'react';
import { useGameStore } from '../store/store';
import { ModalFrame } from './ui/ModalFrame';
import { Button } from './ui/Button';
import { selectAvailableDialogues } from '../store/selectors/dialogueSelectors';
import { AnimatedText } from './AnimatedText';
import { ChoiceButton } from './ChoiceButton';
import { LoadingSpinner } from './LoadingSpinner';
import { cn } from '../lib/utils';
import { Companion } from '../types';

interface CompanionHubModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export const CompanionHubModal: React.FC<CompanionHubModalProps> = ({ isOpen, onClose }) => {
    const { party, activeDialogue, currentDialogueNode, startDialogue, advanceDialogue, endDialogue } = useGameStore();
    const availableDialogues = useGameStore(selectAvailableDialogues);
    const [selectedCompanionId, setSelectedCompanionId] = React.useState<string | null>(null);

    const handleClose = () => {
        if (activeDialogue) {
            // If in conversation, end it properly first
            endDialogue();
        }
        setSelectedCompanionId(null);
        onClose();
    };

    const activeCompanion = useMemo(() => party.find(c => c.id === selectedCompanionId), [party, selectedCompanionId]);
    const companionDialogues = useMemo(() => availableDialogues.filter(d => d.companionId === selectedCompanionId), [availableDialogues, selectedCompanionId]);

    const renderConversationView = () => {
        if (!currentDialogueNode) return <LoadingSpinner />;

        // Find the companion who is speaking (based on activeDialogue)
        const speaker = party.find(c => c.id === activeDialogue?.companionId);

        return (
            <div className="flex flex-col h-full">
                <div className="flex-grow p-4 overflow-y-auto bg-black/30 rounded-md border border-stone-700/50 mb-4">
                     {/* Sprite for context */}
                    <div className="flex items-center gap-4 mb-6 border-b border-stone-600/50 pb-4">
                         <div className="w-16 h-16 rounded-full border-2 border-amber-700 overflow-hidden flex-shrink-0 bg-stone-800">
                             {speaker?.spriteUrl ? (
                                <img src={speaker.spriteUrl} alt={speaker.name} className="w-full h-full object-cover" />
                             ) : <div className="w-full h-full bg-stone-700" />}
                         </div>
                         <div>
                             <h3 className="font-medieval text-2xl text-amber-200">{speaker?.name}</h3>
                             <p className="text-stone-400 text-sm italic">Listening...</p>
                         </div>
                    </div>

                    <div className="text-xl text-gray-200 leading-relaxed">
                        <AnimatedText key={currentDialogueNode.id} text={currentDialogueNode.text} />
                    </div>
                </div>

                <div className="flex-shrink-0">
                    {currentDialogueNode.choices.map((choice, idx) => (
                        <ChoiceButton 
                            key={idx} 
                            text={choice.text} 
                            onClick={() => advanceDialogue(choice)} 
                        />
                    ))}
                </div>
            </div>
        );
    };

    const renderCompanionSelectionView = () => {
        if (party.length === 0) {
            return (
                <div className="flex items-center justify-center h-full text-stone-500">
                    <p>You are traveling alone.</p>
                </div>
            );
        }

        return (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                {party.map(companion => (
                    <button
                        key={companion.id}
                        onClick={() => setSelectedCompanionId(companion.id)}
                        className="flex flex-col items-center bg-stone-800/60 p-4 rounded-lg border-2 border-stone-600 hover:border-amber-500 hover:bg-stone-700/80 transition-all group"
                    >
                        <div className="w-24 h-24 rounded-full border-2 border-stone-500 overflow-hidden mb-3 bg-black">
                            <img src={companion.spriteUrl} alt={companion.name} className="w-full h-full object-cover" />
                        </div>
                        <h3 className="font-medieval text-xl text-amber-100 group-hover:text-white">{companion.name}</h3>
                        <p className="text-xs text-stone-400">{companion.characterClass}</p>
                    </button>
                ))}
            </div>
        );
    }

