// Type alias for Zustand's `get` and `set` to make the constructor cleaner.
// Use the full GameStore type to ensure the manager has access to all actions from all slices.
type GetState = () => GameStore;
type SetState = (partial: Partial<GameStore> | ((state: GameStore) => Partial<GameStore>)) => void;

/**
