const getModifier = (statValue: number) => Math.floor((statValue - 10) / 2);


/**
 * @class CombatManager
 * Encapsulates all logic and state transitions for the turn-based combat system.
 * This class is instantiated within the main Zustand store and operates on the global state
 * via `getState` and `setState` passed during its construction. This approach isolates the complex
 * combat logic from the main store, promoting modularity and easier testing.
 */
export class CombatManager {
    private getState: GetState;
    private setState: SetState;

    /**
     * @param getState A function to get the current global game state.
     * @param setState A function to update the global game state.
     */
    constructor(getState: GetState, setState: SetState) {
        this.getState = getState;
        this.setState = setState;
    }

    /**
     * Initializes a new combat encounter.
     * It builds the list of combatants from the player, companion, and enemy data,
     * calculates the turn order, and sets up the initial combat state.
     * @param scene The combat scene configuration containing enemies and outcomes.
     */
    public startCombat = (scene: { enemies: { enemyId: string; count: number }[]; onVictoryScene: string; onDefeatScene: string; temporaryCompanions?: { allyId: string; count: number }[]; }) => {
        this.setState(state => {
            if (!state.player || state.combatState) return state;
            const { player, party } = state;

            const combatants: Combatant[] = [];

            // Helper functions to create combatant objects from different data sources.
            const createCombatantFromPlayer = (p: PlayerCharacter): Combatant => ({
                id: 'player', originalId: 'player', name: p.name, spriteUrl: p.spriteUrl, type: 'player',
                maxHp: p.stats.maxHp, currentHp: p.stats.hp, maxMana: p.stats.maxMana, currentMana: p.stats.mana,
                maxStamina: p.stats.maxStamina, currentStamina: p.stats.stamina,
                speed: p.stats.dexterity, armorClass: 10 + getModifier(p.stats.dexterity), // simplified AC
                attackBonus: 4 + getModifier(p.stats[p.characterClass.scalesWith?.[0] || 'strength']),
                damage: p.equipment.mainHand?.damage || { amount: 1 + getModifier(p.stats.strength), type: DamageType.BLUDGEONING },
                isDefeated: false, statusEffects: [],
                martialAbilities: p.martialAbilities, spells: p.spells,
            });

            const createCombatantFromCompanion = (c: Companion): Combatant => ({
                id: c.id, originalId: c.id, name: c.name, spriteUrl: c.spriteUrl, type: 'companion',
                maxHp: c.stats.maxHp, currentHp: c.stats.hp, maxStamina: c.stats.maxStamina, currentStamina: c.stats.stamina,
                speed: c.stats.dexterity, armorClass: 10 + getModifier(c.stats.dexterity),
                attackBonus: 3 + getModifier(c.stats[COMPANIONS[c.id].characterClass === 'Ranger' ? 'dexterity' : 'strength']),
                damage: c.equipment.mainHand?.damage || { amount: 1 + getModifier(c.stats.strength), type: DamageType.BLUDGEONING },
                isDefeated: false, statusEffects: [],
                martialAbilities: c.martialAbilities, spells: c.spells, personality: c.personality,
            });

            const createCombatantFromEnemy = (e: Enemy, uniqueId: string): Combatant => ({
                id: uniqueId, originalId: e.id, name: e.name, spriteUrl: e.imageUrl, type: 'enemy',
                maxHp: e.stats.maxHp, currentHp: e.stats.maxHp, maxMana: e.stats.maxMana, currentMana: e.stats.maxMana,
                maxStamina: e.stats.maxStamina, currentStamina: e.stats.maxStamina,
                speed: e.stats.speed, armorClass: e.stats.armorClass, attackBonus: e.stats.attackBonus, damage: e.stats.damage,
                isDefeated: false, statusEffects: [],
                martialAbilities: e.stats.martialAbilities, personality: e.stats.personality,
            });

            const createCombatantFromAlly = (a: Ally, uniqueId: string): Combatant => ({
                id: uniqueId, originalId: a.id, name: a.name, spriteUrl: a.imageUrl, type: 'companion',
                maxHp: a.stats.maxHp, currentHp: a.stats.maxHp, maxStamina: a.stats.maxStamina, currentStamina: a.stats.maxStamina,
                speed: a.stats.speed, armorClass: a.stats.armorClass, attackBonus: a.stats.attackBonus, damage: a.stats.damage,
                isDefeated: false, statusEffects: [],
                martialAbilities: a.stats.martialAbilities, personality: a.stats.personality,
            });

            // Build the combatants list
            combatants.push(createCombatantFromPlayer(player));
            party.forEach(companion => {
                combatants.push(createCombatantFromCompanion(companion));
            });
            scene.enemies.forEach(({ enemyId, count }) => {
                const enemyData = getEnemy(enemyId);
                if (enemyData) for (let i = 0; i < count; i++) combatants.push(createCombatantFromEnemy(enemyData, `${enemyId}_${i}`));
            });
            scene.temporaryCompanions?.forEach(({ allyId, count }) => {
                const allyData = getAlly(allyId);
                if (allyData) for (let i = 0; i < count; i++) combatants.push(createCombatantFromAlly(allyData, `${allyId}_${i}`));
            });

            // Determine turn order based on speed
            const turnOrder = [...combatants].sort((a, b) => b.speed - a.speed).map(c => c.id);

            const initialCombatState: CombatState = {
                combatants, turnOrder, currentTurnId: turnOrder[0], isProcessingEvent: false, eventQueue: [],
                log: [createLogEntry('Combat begins!', 'system')],
                onVictoryScene: scene.onVictoryScene, onDefeatScene: scene.onDefeatScene,
                isFinished: null, rewards: null,
                // FIX: Added missing 'playerActionState' property to conform to the CombatState type.
                playerActionState: { type: null, isAwaitingTarget: false },
            };

            // Queue the first turn start event
            const firstEvent: CombatEvent = { type: 'TURN_START', combatantId: turnOrder[0] };

            return { combatState: { ...initialCombatState, eventQueue: [firstEvent] } };
        });
    }

    /**
     * Adds a new event to the combat event queue.
     * The combat system processes events from this queue one by one.
     * @param event The CombatEvent to add.
     * @param atStart If true, prepends the event to the queue, giving it priority.
     */
    public addCombatEvent = (event: CombatEvent, atStart = false) => {
        this.setState(state => {
            if (!state.combatState) return state;
            const newQueue = atStart ? [event, ...state.combatState.eventQueue] : [...state.combatState.eventQueue, event];
            return { combatState: { ...state.combatState, eventQueue: newQueue } };
        });
    }

    /**
     * Handles the player's chosen action during their turn by adding it to the event queue.
     * @param action The details of the action being performed.
     * @param targetId The ID of the target, if any.
     */
    public playerChooseAction = (action: ActionDetails, targetId?: string) => {
        const { combatState } = this.getState();
        if (!combatState || combatState.currentTurnId !== 'player') return;

        this.addCombatEvent({ type: 'ACTION_CHOSEN', sourceId: 'player', targetId, action });
    }

    /**
     * Processes the next event in the queue. This is the core of the combat engine.
     * It uses a state machine-like approach to handle different event types, updating the
     * combat state and queueing subsequent events as needed.
     */
    public processNextCombatEvent = async () => {
        const { combatState } = this.getState();
        if (!combatState || combatState.isProcessingEvent || combatState.eventQueue.length === 0) return;

        this.setState(state => ({ combatState: { ...state.combatState!, isProcessingEvent: true } }));

        // Dequeue the next event
        const event = this.getState().combatState!.eventQueue[0];
        this.setState(state => ({ combatState: { ...state.combatState!, eventQueue: state.combatState!.eventQueue.slice(1) }}));

        let newEvents: CombatEvent[] = [];
        const currentCombatState = this.getState().combatState!;

        switch (event.type) {
            case 'TURN_START': {
                const combatant = currentCombatState.combatants.find(c => c.id === event.combatantId)!;
                newEvents.push({ type: 'LOG_MESSAGE', message: `${combatant.name}'s turn.`, logType: 'system' });

                // Tick start-of-turn effects
                // This part of the logic has been moved to TURN_END to correctly handle durations.
                // However, we can check for stun here to skip the turn.

                if (combatant.statusEffects.some(e => e.type === 'STUNNED')) {
                    newEvents.push({ type: 'LOG_MESSAGE', message: `${combatant.name} is stunned!`, logType: 'info' });
                    newEvents.push({ type: 'TURN_END', combatantId: combatant.id });
                } else if (combatant.type !== 'player') {
                    const aiAction = await getAIAction(combatant, currentCombatState);
                    if (aiAction.type === 'idle') {
                        newEvents.push({ type: 'LOG_MESSAGE', message: `${combatant.name} hesitates.`, logType: 'info' });
                        newEvents.push({ type: 'TURN_END', combatantId: combatant.id });
                    } else {
                        const { targetId, ...actionDetails } = aiAction;
                        newEvents.push({ type: 'ACTION_CHOSEN', sourceId: combatant.id, targetId: targetId, action: actionDetails });
                    }
                }
                break;
            }
            case 'ACTION_CHOSEN': {
                const { sourceId, targetId, action } = event;
                const source = currentCombatState.combatants.find(c => c.id === sourceId)!;
                const target = currentCombatState.combatants.find(c => c.id === targetId)!;

                let actionId: string | undefined;

                if (action.type === 'attack') {
                    actionId = 'basic-attack';
                } else if (action.type === 'spell') {
                    const spellData = await getSpell(action.spellSlug!);
                    if (spellData) {
                         if (source.currentMana! >= spellData.manaCost) {
                            this.setState(state => ({ combatState: { ...state.combatState!, combatants: state.combatState!.combatants.map(c => c.id === sourceId ? { ...c, currentMana: c.currentMana! - spellData.manaCost } : c) } }));
                            actionId = spellData.actionId;
                        } else {
                             newEvents.push({ type: 'LOG_MESSAGE', message: `${source.name} does not have enough mana.`, logType: 'info' });
                        }
                    }
                } else if (action.type === 'ability') {
                    const abilityData = MARTIAL_ABILITIES[action.abilityId!];
                     if (abilityData) {
                         if (source.currentStamina! >= abilityData.staminaCost) {
                            this.setState(state => ({ combatState: { ...state.combatState!, combatants: state.combatState!.combatants.map(c => c.id === sourceId ? { ...c, currentStamina: c.currentStamina! - abilityData.staminaCost } : c) } }));
                            actionId = abilityData.actionId;
                        } else {
                             newEvents.push({ type: 'LOG_MESSAGE', message: `${source.name} does not have enough stamina.`, logType: 'info' });
                        }
                    }
                }

                if (actionId && ACTION_REGISTRY[actionId]) {
                    const generatedEvents = ACTION_REGISTRY[actionId].resolve(source, target, currentCombatState.combatants);
                    newEvents.push(...generatedEvents);
                }

                newEvents.push({ type: 'TURN_END', combatantId: sourceId });
                break;
            }
            case 'ATTACK_RESOLVED': {
                if (event.hit) {
                    const abilityName = event.abilityId ? (MARTIAL_ABILITIES[event.abilityId]?.name || getSpell(event.abilityId)?.then(s => s?.name) || event.abilityId) : '';
                    const sourceName = currentCombatState.combatants.find(c=>c.id === event.sourceId)?.name || 'Unknown';
                    const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';

                    const message = `${sourceName} ${abilityName ? `uses ${abilityName} and ` : ''}hits ${targetName} for ${event.damage} ${event.damageType} damage.`;
                    newEvents.push({ type: 'LOG_MESSAGE', message, logType: 'damage' });

                    this.setState(state => {
                        const newCombatants = state.combatState!.combatants.map(c => c.id === event.targetId ? {...c, currentHp: Math.max(0, c.currentHp - event.damage)} : c);
                        return { combatState: {...state.combatState!, combatants: newCombatants}};
                    });
                    const target = this.getState().combatState!.combatants.find(c => c.id === event.targetId)!;
                    if (target.currentHp <= 0) newEvents.push({ type: 'COMBATANT_DEFEATED', combatantId: target.id });
                } else {
                     const sourceName = currentCombatState.combatants.find(c=>c.id === event.sourceId)?.name || 'Unknown';
                     const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';
                    newEvents.push({ type: 'LOG_MESSAGE', message: `${sourceName} misses ${targetName}.`, logType: 'miss' });
                }
                break;
            }
            case 'HEAL_RESOLVED': {
                 const sourceName = currentCombatState.combatants.find(c=>c.id === event.sourceId)?.name || 'Unknown';
                 const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';
                 newEvents.push({ type: 'LOG_MESSAGE', message: `${sourceName} heals ${targetName} for ${event.amount} HP.`, logType: 'heal' });
                 this.setState(state => {
                     const newCombatants = state.combatState!.combatants.map(c => c.id === event.targetId ? {...c, currentHp: Math.min(c.maxHp, c.currentHp + event.amount)} : c);
                     return { combatState: {...state.combatState!, combatants: newCombatants}};
                 });
                 break;
            }
            case 'STATUS_APPLIED': {
                 const targetName = currentCombatState.combatants.find(c=>c.id === event.targetId)?.name || 'Unknown';
                 newEvents.push({ type: 'LOG_MESSAGE', message: `${targetName} is now ${event.effect.name}.`, logType: 'status' });
                 this.setState(state => {
                     const newCombatants = state.combatState!.combatants.map(c => c.id === event.targetId ? {...c, statusEffects: [...c.statusEffects, event.effect]} : c);
                     return { combatState: {...state.combatState!, combatants: newCombatants}};
                 });
                 break;
            }
            case 'COMBATANT_DEFEATED': {
                const defeatedName = currentCombatState.combatants.find(c=>c.id === event.combatantId)?.name || 'Unknown';
                newEvents.push({ type: 'LOG_MESSAGE', message: `${defeatedName} has been defeated!`, logType: 'system' });
                this.setState(state => {
                     const newCombatants = state.combatState!.combatants.map(c => c.id === event.combatantId ? {...c, isDefeated: true, currentHp: 0} : c);
                     const partyAlive = newCombatants.some(c => (c.type === 'player' || c.type === 'companion') && !c.isDefeated);
                     const enemiesAlive = newCombatants.some(c => c.type === 'enemy' && !c.isDefeated);

                     const outcomeEvents: CombatEvent[] = [];
                     if (!partyAlive) outcomeEvents.push({ type: 'COMBAT_END', outcome: 'defeat' });
                     else if (!enemiesAlive) outcomeEvents.push({ type: 'COMBAT_END', outcome: 'victory' });

                     if (outcomeEvents.length > 0) {
                        this.addCombatEvent(outcomeEvents[0], true);
                     }

                     return { combatState: {...state.combatState!, combatants: newCombatants}};
                 });
                break;
            }
            case 'TURN_END': {
                const currentTurnId = event.combatantId;

                const endOfTurnUpdate = () => {
                    const currentState = this.getState().combatState;
                    if(!currentState) return;

                    const endOfTurnEvents: CombatEvent[] = [];

                    const newCombatants = currentState.combatants.map(c => {
                        if (c.id === currentTurnId) {
                            const updatedEffects = c.statusEffects
                                .map(effect => ({ ...effect, duration: effect.duration - 1 }))
                                .filter(effect => {
                                    if (effect.duration <= 0) {
                                        endOfTurnEvents.push({ type: 'LOG_MESSAGE', message: `${effect.name} has worn off for ${c.name}.`, logType: 'status' });
                                        return false;
                                    }
                                    return true;
                                });
                            return { ...c, statusEffects: updatedEffects };
                        }
                        return c;
                    });

                    this.setState(state => ({ combatState: {...state.combatState!, combatants: newCombatants}}));

                    endOfTurnEvents.forEach(e => this.addCombatEvent(e));

                    const turnOrder = currentState.turnOrder;
                    const currentIndex = turnOrder.indexOf(currentTurnId);
                    const nextIndex = (currentIndex + 1) % turnOrder.length;

                    let nextCombatantId = turnOrder[nextIndex];
                    let loopCount = 0;
                    while(this.getState().combatState!.combatants.find(c => c.id === nextCombatantId)?.isDefeated) {
                        nextCombatantId = turnOrder[(turnOrder.indexOf(nextCombatantId) + 1) % turnOrder.length];
                        loopCount++;
                        if (loopCount > turnOrder.length) break;
                    }
                    this.addCombatEvent({ type: 'TURN_START', combatantId: nextCombatantId }, true);
                    this.setState(state => ({ combatState: {...state.combatState!, currentTurnId: nextCombatantId }}));
                };

                endOfTurnUpdate();
                break;
            }
            case 'COMBAT_END': {
                let rewards = null;
                if (event.outcome === 'victory') {
                    const xp = currentCombatState.combatants.filter(c => c.type === 'enemy' && c.originalId).reduce((total, c) => total + (getEnemy(c.originalId!)?.stats.xpValue || 0), 0);
                    rewards = { xp, loot: [] };
                }
                this.setState(state => ({ combatState: {...state.combatState!, isFinished: event.outcome, rewards }}));
                break;
            }
            case 'LOG_MESSAGE': {
                 this.setState(state => ({ combatState: {...state.combatState!, log: [...state.combatState!.log, createLogEntry(event.message, event.logType)] }}));
                break;
            }
        }

        newEvents.reverse().forEach(e => this.addCombatEvent(e, true));
        this.setState(state => ({ combatState: { ...state.combatState!, isProcessingEvent: false } }));
    }

    /**
     * Cleans up after combat is finished. It applies rewards (XP, loot), updates the player's
     * health, and transitions to the appropriate post-combat scene.
     */
    public concludeCombat = () => {
        const { combatState, player, gainXp, addItemToPlayerInventory, advanceScene } = this.getState();
        if (!combatState || !combatState.isFinished) return;

        if (combatState.isFinished === 'victory' && combatState.rewards) {
            gainXp(combatState.rewards.xp);
            combatState.rewards.loot.forEach(loot => addItemToPlayerInventory(loot.item));
        }

        const newPlayerStats = { ...player!.stats };
        const playerInCombat = combatState.combatants.find(c => c.id === 'player');
        if (playerInCombat) {
            newPlayerStats.hp = playerInCombat.currentHp;
            newPlayerStats.mana = playerInCombat.currentMana!;
        }

        const sceneId = combatState.isFinished === 'victory' ? combatState.onVictoryScene : combatState.onDefeatScene;

        this.setState({ combatState: null, player: player ? { ...player, stats: newPlayerStats } : null, });
        advanceScene({ text: 'Combat Ends', nextScene: sceneId });
    }
}
